mapper.select:
SELECT r.*, v.name AS guest_name, v.phone AS guest_phone, c.check_in_date AS guest_check_in_date, c.check_out_date AS guest_check_out_date, c.id AS check_in_id FROM biz_dorm_room r LEFT JOIN biz_check_in c ON r.id = c.room_id AND c.deleted = 0 AND c.check_in_status IN (1, 4) LEFT JOIN biz_visitor v ON c.visitor_id = v.id WHERE r.deleted = 0
AND r.status = #{status}
ORDER BY r.room_no ASC

SELECT r.* FROM biz_dorm_room r
WHERE r.deleted = 0 AND r.status = 1
AND r.id NOT IN (
    SELECT c.room_id FROM biz_check_in c
    WHERE c.deleted = 0
    AND c.check_in_status IN (1)
    AND c.check_in_date < #{endDate}
    AND c.check_out_date > #{startDate}
)
ORDER BY r.room_no ASC
